INSERT INTO "programs" VALUES('L2/scada/programs/acg/auth.json','2.5','{"Profile": {"provider": "e[discord|github]", "id": "s", "username": "s", "avatar": "s"}}','auth','L2/scada/gateway/scripts/auth.js',NULL,'{"module": "L2/scada/gateway/scripts/auth.js", "name": "auth", "§": "2.5", "↑🖥️": ["auth.profile", "auth.signedIn"], "→": [{"flow": "JSON.parse(localStorage.acg.profile) ∨ ∅", "name": "load", "out": "🔑?"}, {"flow": "localStorage.set ⊕ publishProfile ⊕ listeners(p) ⊕ paint()", "in": "p:🔑?", "name": "save"}, {"flow": "AUTH.write(profile,🏗️Profile) ⊕ AUTH.write(signedIn,b)", "name": "publishProfile"}, {"flow": "→ https://discord.com/oauth2/authorize?response_type=token (implicit grant, pure browser)", "name": "discordLogin"}, {"flow": "GET /api/users/@me → save(🏗️Profile)", "in": "token:s", "name": "discordFinish"}, {"flow": "POST {proxyUrl}/device/code → open verification_uri ⊕ prompt(code) ⊕ poll /access_token", "name": "githubLogin"}, {"flow": "GET api.github.com/user → save(🏗️Profile)", "in": "token:s", "name": "githubFinish"}, {"flow": "if location.hash has access_token → state-check ⊕ discordFinish", "name": "handleRedirect"}, {"flow": "rebuild #auth nav (logged-in chip ∨ GitHub/Discord buttons)", "name": "paint"}, {"flow": "paint() ⊕ handleRedirect()", "name": "startAuth"}, {"flow": "listeners.add(fn)", "in": "fn", "name": "onProfileChange", "out": "unsub"}, {"flow": "save(∅)", "name": "logout"}], "↓🖥️": [], "和": true, "🏗️": {"Profile": {"avatar": "s", "id": "s", "provider": "e[discord|github]", "username": "s"}}, "📦": {"listeners": "Set<(profile)→void>", "profile": "🔑? (Profile UDT from localStorage)"}}');
INSERT INTO "programs" VALUES('L2/scada/programs/acg/chat.json','2.4','{"ChatMsg": {"role": "e[user|ai|system]", "len": "i", "ts": "ms"}, "📨": {"t": "\"msg\"", "id": "s20", "txt": "s"}}','chat','L2/scada/gateway/scripts/chat.js',NULL,'{"module": "L2/scada/gateway/scripts/chat.js", "name": "chat", "§": "2.4", "↑🖥️": ["chat.msgsOut", "chat.lastMsgAt"], "→": [{"flow": "DOM.append(.msg) ⊕ scroll", "in": "pid:s20?, nm:s, em:s, txt:s, sys:b=false, avatar:s?=null", "name": "addMsg"}, {"flow": "read(#cIn) → bcast(📨) ⊕ addMsg(self) ⊕ CHAT.inc(msgsOut) ⊕ CHAT.write(lastMsgAt)", "in": "∅", "name": "send"}], "↓🖥️": ["auth.profile"], "和": true, "🏗️": {"ChatMsg": {"len": "i", "role": "e[user|ai|system]", "ts": "ms"}, "📨": {"id": "s20", "t": "\"msg\"", "txt": "s"}}}');
