INSERT INTO "programs" VALUES('L2/scada/programs/acg/main.json','2.0','🚀','main','L2/scada/gateway/scripts/main.js','entry · wires handlers · seeds sys.* · starts monitor, version, auth, sandbox-bridge','{"desc": "entry · wires handlers · seeds sys.* · starts monitor, version, auth, sandbox-bridge", "module": "L2/scada/gateway/scripts/main.js", "name": "main", "§": "2.0", "↑🖥️": ["sys.startedAt", "sys.uptimeSec", "sys.myId", "sys.myNm", "sys.myEm", "sys.trackerCount", "sys.userAgent"], "→": [{"flow": "profile?.username ∨ myNm", "name": "meLabel", "out": "s"}, {"flow": "#mId.text=meLabel ⊕ wire(#jBtn,#cIn,#sBtn,#scBtn) ⊕ SYS.write(startedAt,myId,myNm,myEm,trackerCount,userAgent) ⊕ startMonitor ⊕ startSandboxBridge ⊕ updPeers ⊕ startVersion ⊕ startAuth ⊕ onProfileChange(→re-hi) ⊕ setTimeout(join,300)", "name": "<init>"}, {"flow": "30s → announce() ⊕ 1s → SYS.uptimeSec++", "name": "<intervals>"}], "和": true, "🎹": {"#cIn.Enter": "send()", "#jBtn.click": "join(#rIn.value ∨ ''acg-guild'')", "#sBtn.click": "send()", "#scBtn.click": "toggleMonitor()", "Ctrl/Cmd+.": "toggleMonitor()"}, "🏗️": "🚀"}');
INSERT INTO "programs" VALUES('L2/scada/programs/acg/p2p.json','2.2','📡','p2p','L2/scada/gateway/scripts/p2p.js','Multi-tracker WebRTC signalling. Fans out to every tracker in TRACKERS[] in parallel; peers find each other via the union of connected trackers, not one chosen tracker. Per-URL reconnect with exponential back-off.','{"desc": "Multi-tracker WebRTC signalling. Fans out to every tracker in TRACKERS[] in parallel; peers find each other via the union of connected trackers, not one chosen tracker. Per-URL reconnect with exponential back-off.", "module": "L2/scada/gateway/scripts/p2p.js", "name": "p2p", "§": "2.2", "↑🖥️": ["room.name", "room.hash", "room.joinedAt", "room.data", "tracker.current", "tracker.state", "tracker.count", "tracker.announces", "tracker.lastAnnounceAt", "tracker.trackers.<idx>", "signal.last", "signal.offersIn", "signal.answersIn", "signal.answersOut"], "→": [{"flow": "SHA1(''acg:''+name) → hex", "in": "name:s", "name": "mkHash", "out": "s40"}, {"flow": "pc.iceGatheringState===''complete'' ∨ timeout", "in": "pc, ms=4000", "name": "waitIce", "out": "Promise"}, {"flow": "∀ i<n → RTCPC ⊕ wire(🔌,uuid) ⊕ createOffer ⊕ waitIce ⊕ schedule PENDING_TTL_MS reap", "in": "n:i", "name": "mkOffers", "out": "a[{offer_id,offer}]"}, {"flow": "RTCPC ⊕ setRemote(offer) ⊕ createAnswer ⊕ waitIce ⊕ sock.send (reply on same tracker)", "in": "msg:o, sock:🔌", "name": "onOffer"}, {"flow": "pending.delete(offer_id) ⊕ setRemote(answer) — first tracker to deliver wins", "in": "msg:o", "name": "onAnswer"}, {"flow": "mkOffers(N_OFFERS) → ∀ open 🔌 → sock.send({action:announce,…})", "in": "∅", "name": "announce"}, {"flow": "if already open/connecting bail ⊕ new WebSocket ⊕ 6s timeout ⊕ onopen: announce(this sock) ⊕ onclose: scheduleReconnect", "in": "url:s", "name": "connectTracker"}, {"flow": "attempts[url]++ ⊕ setTimeout(connectTracker, back-off[min(n, max)])", "in": "url:s", "name": "scheduleReconnect"}, {"flow": "close all 🔌 ⊕ clear(pm, pending, timers) ⊕ ∀ TRACKERS → connectTracker(url) in parallel", "in": "rName:s", "name": "join"}, {"flow": "∀ 🔌∈pm.dcs.open → dc.send(JSON)", "in": "msg:o", "name": "bcast", "out": "i peerCount"}, {"flow": "openSockets().length > 0", "name": "wsReady", "out": "b"}], "↓🖥️": [], "⚙️": {"CONNECT_TIMEOUT_MS": 6000, "PENDING_TTL_MS": 60000, "RECONNECT_BACKOFF_MS": "[3000, 6000, 12000, 30000, 60000]"}, "和": true, "🏗️": "📡", "📦": {"hash": "s40", "pending": "m offerId → RTCPeerConnection", "reTimer": "timeoutId?", "reconnectAttempts": "m url → i", "reconnectTimers": "m url → timeoutId", "room": "s", "sockets": "m url → 🔌"}}');
