INSERT INTO "programs" VALUES('L2/scada/programs/acg/peers.json','2.3','{"Peer": {"id": "s20", "name": "s", "emoji": "s", "avatar": "s?", "state": "e[open|closed]", "channels": "i", "connectedAt": "ms", "msgsIn": "i", "msgsOut": "i", "lastSeen": "ms"}}','peers','L2/scada/gateway/scripts/peers.js',NULL,'{"module": "L2/scada/gateway/scripts/peers.js", "name": "peers", "§": "2.3", "↑🖥️": ["peers.<peerId>", "room.peerCount"], "→": [{"flow": "auth.profile ∨ {myNm,myEm}", "name": "meCard", "out": "{name:s,emoji:s,avatar:s?}"}, {"flow": "PEERS.write(pid, 🏗️Peer) ∨ del if ∅dcs", "in": "pid:s20", "name": "publishPeer"}, {"flow": "ROOM.write(peerCount, |pm ∩ open| + 1)", "name": "publishPeerCount"}, {"flow": "🔌.on{open→pm.add ⊕ send👋 ⊕ publishPeer, close→pm.delete, msg→parse{hi|msg} ⊕ updPeers ⊕ publishPeer}", "in": "🔌,rid:s20", "name": "wire"}, {"flow": "rebuild #pList ⊕ publishPeerCount", "name": "updPeers"}], "↓🖥️": ["auth.profile"], "和": true, "🏗️": {"Peer": {"avatar": "s?", "channels": "i", "connectedAt": "ms", "emoji": "s", "id": "s20", "lastSeen": "ms", "msgsIn": "i", "msgsOut": "i", "name": "s", "state": "e[open|closed]"}}, "📦": {"pm": "m peerId:s20 → 🏗️👥{ name:s emoji:s avatar:s? dcs:Set<🔌> connectedAt:ms msgsIn:i msgsOut:i lastSeen:ms }"}}');
INSERT INTO "programs" VALUES('L2/scada/programs/acg/sandbox-bridge.json','4.1','🛰️','sandbox-bridge (host side)','L2/scada/gateway/scripts/sandbox-bridge.js',NULL,'{"module": "L2/scada/gateway/scripts/sandbox-bridge.js", "name": "sandbox-bridge (host side)", "§": "4.1", "↑🖥️": ["sandbox.bridgeOpen", "sandbox.channel", "sandbox.<source>.lastEventAt", "sandbox.<source>.lastEvent", "sandbox.<source>.<path>    (on type===''tag'')", "sandbox.<source>.event.<type>", "sandbox.<source>.events.<type>.count"], "→": [{"flow": "type===''tag'' ? tags.write(''sandbox.''+source+''.''+path, value, {udt,quality}) : tags.write(''sandbox.''+source+''.event.''+type, env) ⊕ tags.inc(''sandbox.''+source+''.events.''+type+''.count'')", "in": "env:{source,type,path?,value?,ts,…}", "name": "onEnvelope"}, {"flow": "new BroadcastChannel ⊕ listen ⊕ tags.write(sandbox.bridgeOpen, true)", "name": "startSandboxBridge"}, {"flow": "ch.close ⊕ tags.write(sandbox.bridgeOpen, false)", "name": "stopSandboxBridge"}], "⚙️": {"CHAN": "acg-mesh"}, "和": true, "🏗️": "🛰️", "📦": {"ch": "BroadcastChannel?"}}');
INSERT INTO "programs" VALUES('L2/scada/programs/acg/scada-monitor.json','3.2','🖥️','monitor','L2/scada/gateway/scripts/scada/monitor.js',NULL,'{"module": "L2/scada/gateway/scripts/scada/monitor.js", "name": "monitor", "§": "3.2", "→": [{"flow": "now | Ns | Nm | Nh | Nd", "in": "ts:ms", "name": "fmtAge", "out": "s"}, {"flow": "primitive ∨ JSON.stringify", "in": "any", "name": "fmtVal", "out": "s"}, {"flow": "tags.list() → filter → <tr class=q-{quality}>", "name": "render"}, {"flow": "rAF-debounce render() when !hidden", "name": "schedule"}, {"flow": "build drawer DOM ⊕ wire filter/close", "name": "mount"}, {"flow": "#scada | #scada?q | #scada/q → open(false) ⊕ filter=q", "name": "applyHash"}, {"flow": "subscribe(''**'',schedule) ⊕ history.replaceState(#scada)", "in": "sync=true", "name": "open"}, {"flow": "unsubscribe ⊕ history.replaceState(path)", "in": "sync=true", "name": "close"}, {"flow": "hidden ? open() : close()", "name": "toggle"}, {"flow": "mount() ⊕ setInterval(render,1000) ⊕ hashchange listener ⊕ applyHash()", "name": "startMonitor"}], "↓🖥️": ["<all>  via subscribe(''**'')"], "和": true, "🏗️": "🖥️", "📐route": {"#scada": "open drawer, no filter", "#scada/q": "open drawer, pre-fill filter=q (slash form)", "#scada?q": "open drawer, pre-fill filter=q", "Ctrl/Cmd+.": "toggle"}, "📦": {"filterIn": "DOM #sc-f", "hidden": "b", "off": "unsub?", "panel": "DOM #scada", "tbody": "DOM #sc-rows"}}');
INSERT INTO "programs" VALUES('L2/scada/programs/acg/scada-tags.json','3.1','🏷️','tags','L2/scada/gateway/scripts/scada/tags.js',NULL,'{"module": "L2/scada/gateway/scripts/scada/tags.js", "name": "tags", "§": "3.1", "↑🖥️": ["<all>"], "→": [{"flow": "''*'' | ''**'' | ''.*'' | ''.**'' | exact", "in": "pat,path", "name": "patternMatches", "out": "b"}, {"flow": "∀ (pat,fns) ∈ subs where match(pat,path) → fn(path,tag)", "in": "path", "name": "notify"}, {"flow": "tags.set ⊕ notify(path)", "in": "path,value,opts={}", "name": "write", "out": "tag"}, {"flow": "write(path, (cur?.value||0)+by, type:Counter)", "in": "path,by=1", "name": "inc"}, {"in": "path", "name": "read", "out": "tag?"}, {"flow": "tags.delete ⊕ notify", "in": "path", "name": "del"}, {"in": "prefix=''''", "name": "list", "out": "[[path,tag],…]"}, {"in": "pattern,fn", "name": "subscribe", "out": "unsub"}, {"in": "path,quality", "name": "setQuality"}, {"flow": "∀ tag.quality=good ∧ ts<now-age → 🟡", "in": "prefix,ageMs", "name": "sweepStale"}], "和": true, "🏗️": "🏷️", "📦": {"subs": "m pattern:s → Set<(path, tag)→void>", "tags": "m path:s → { value:any quality:🟢|🟡|🔴 ts:ms type:s? }"}}');
