INSERT INTO "programs" VALUES('L2/scada/programs/web-llm/fs-panel.json','4.2.4','📁','fs-panel','L4/sandbox/web-llm/modules/fs-panel.js',NULL,'{"module": "L4/sandbox/web-llm/modules/fs-panel.js", "name": "fs-panel", "§": "4.2.4", "↑🖥️(via 🛰️)": ["sandbox.web-llm.fs.fileCount", "sandbox.web-llm.fs.files", "sandbox.web-llm.fs.currentPreview", "sandbox.web-llm.git.commitCount", "sandbox.web-llm.git.branch", "sandbox.web-llm.git.lastCommit (🏗️Commit UDT)"], "→": [{"flow": "listFiles(''/'') → rebuild #file-list ⊕ FS.write(fileCount,files)", "name": "refreshFileList"}, {"flow": "readFile → if html → showPreview", "in": "path", "name": "selectFile"}, {"flow": "getPreviewableFiles → rebuild #preview-tabs", "name": "refreshPreviewTabs"}, {"flow": "getPreviewHTML → iframe.srcdoc ⊕ FS.write(currentPreview,path)", "in": "path", "name": "showPreview"}, {"flow": "iframe hide ⊕ FS.del(currentPreview)", "name": "clearPreview"}, {"flow": "getLog(10) → rebuild #commit-log ⊕ GIT.write(commitCount,branch,lastCommit)", "name": "refreshCommitLog"}, {"flow": "commitChanges ⊕ refreshCommitLog", "in": "msg:s", "name": "manualCommit"}], "和": true, "🏗️": "📁", "📦": {"currentPreview": "s?", "selectedFile": "s?"}}');
INSERT INTO "programs" VALUES('L2/scada/programs/web-llm/main.json','4.2.0','🚀','main (web-llm)','L4/sandbox/web-llm/modules/main.js',NULL,'{"module": "L4/sandbox/web-llm/modules/main.js", "name": "main (web-llm)", "§": "4.2.0", "↑🖥️(via 🛰️)": ["sandbox.web-llm.sys.startedAt", "sandbox.web-llm.sys.userAgent", "sandbox.web-llm.chat.*"], "→": [{"flow": "MODELS → #model-select <option>s", "name": "hydrateSelect"}, {"flow": "#gpu-status.text+class ∨ disable load button", "name": "checkGPU→UI"}, {"flow": "loadModel(id, progressCb→#load-bar/#load-status) ⊕ #model-status ⊕ startSandbox", "name": "load.onclick"}, {"flow": "startSandbox() w/o model", "name": "skip.onclick"}, {"flow": "SYS.write(startedAt,userAgent) ⊕ initRepo ⊕ refreshFileList/CommitLog ⊕ configureVoice(on*) ⊕ setupMic ⊕ setupRecognition ⊕ startListeningAuto ⊕ setInterval(updateEmotionDots,200)", "name": "startSandbox"}, {"flow": "emotionSnapshot → user bubble ⊕ build system+history → streamChat → incremental updateMsgText ⊕ parseAndRunAll (auto preview html) ⊕ if any tool → follow-up streamChat ⊕ refreshFileList/CommitLog", "in": "text:s", "name": "sendMessage"}, {"flow": "snap.values[k] → .emo-dot opacity+active", "name": "updateEmotionDots"}], "和": true, "🎹": {"#btn-commit.click": "prompt → manualCommit ⊕ logRow", "#btn-mic.click": "toggleListening ⊕ .active", "#btn-new-repo.click": "prompt → initRepo ⊕ clearPreview ⊕ refresh", "#btn-refresh-preview.click": "hasPreview? → showPreview(getCurrentPreview)", "#btn-send.click": "sendMessage(value)", "#chat-input.Enter": "sendMessage(value)"}, "🏗️": "🚀"}');
INSERT INTO "programs" VALUES('L2/scada/programs/web-llm/mcp-tools-engine.json','4.2.5','{"VFile": "path:s, type:e, size:i, mtime:ms", "Directory": "path:s, entries:a[s], fileCount:i, mtime:ms", "FileTree": "root:s, nodes:a[{path,type,size?}], fileCount:i", "Commit": "id:s7, message:s, ts:ms, files:i", "Branch": "name:s, head:s7?, commitCount:i", "Status": "clean:b, added:a[s], modified:a[s], deleted:a[s], commits:i", "Diff": "ref:s?, added:a[s], modified:a[s], deleted:a[s]", "Preview": "path:s, sizeBytes:i, inlined:a[{path,kind}], ts:ms", "ExportArtifact": "format:e[json|bundle], size:i, ts:ms", "Scaffold": "kind:e[vanilla|spa|markdown|canvas], files:a[s], entry:s?", "ToolCall": "name:s, args:o, ok:b, result:s?, ts:ms"}','mcp-tools-engine','L4/sandbox/web-llm/modules/mcp-tools-engine.js','Virtual filesystem + git-lite + previewer + scaffolds + fenced LLM-tool parser/dispatcher. The monolithic mcp-tools-engine.js is now a thin re-export shim; every concern lives in its own file under mcp/.','{"desc": "Virtual filesystem + git-lite + previewer + scaffolds + fenced LLM-tool parser/dispatcher. The monolithic mcp-tools-engine.js is now a thin re-export shim; every concern lives in its own file under mcp/.", "module": "L4/sandbox/web-llm/modules/mcp-tools-engine.js", "modules_split": ["L4/sandbox/web-llm/modules/mcp/repo.js", "L4/sandbox/web-llm/modules/mcp/vfs.js", "L4/sandbox/web-llm/modules/mcp/git.js", "L4/sandbox/web-llm/modules/mcp/preview.js", "L4/sandbox/web-llm/modules/mcp/scaffold.js", "L4/sandbox/web-llm/modules/mcp/tools.js"], "name": "mcp-tools-engine", "tags": "L4/sandbox/web-llm/tags.json", "udts": "L4/sandbox/web-llm/udts.json", "§": "4.2.5", "↑🛰️ (sandbox.web-llm via bridge)": ["create_file", "edit_file", "patch_file", "delete_file", "mkdir", "mv", "cp", "tree", "init_repo", "commit", "status", "diff", "checkout", "branch", "preview", "bundle", "scaffold", "export", "import", "tool_call"], "→git (mcp/git.js)": ["initRepo(name) · commitChanges(msg) · getLog(n=20) · getDiff(ref?)", "getStatus() · checkout(ref) · branch(name) · listBranches() · getRepoState()", "exportRepo() · importRepo(json)"], "→llm-tools (mcp/tools.js)": ["parseToolCalls(text) · executeTool(name,args) · buildToolSystemPrompt()"], "→preview (mcp/preview.js)": ["getPreviewableFiles() · getPreviewHTML(path)", "getPreviewBlobUrl(path) · bundle(path)"], "→scaffold (mcp/scaffold.js)": ["scaffold(kind) · SCAFFOLD_KINDS = [vanilla, spa, markdown, canvas]"], "→vfs (mcp/vfs.js)": ["createFile(path,content?) · editFile(path,content) · patchFile(path,old,new)", "deleteFile(path) · readFile(path) · listFiles(prefix=''/'') · searchFiles(query) · getAllFiles()", "mkdir(path) · moveFile(from,to) · copyFile(from,to) · tree(prefix=''/'')"], "⚡dispatch": ["create_file", "edit_file", "patch_file", "delete_file", "read_file", "list_files", "search_files", "mkdir", "mv", "cp", "tree", "commit", "status", "diff", "log", "branch", "checkout", "preview", "bundle", "scaffold", "export", "import"], "和": true, "🏗️": {"Branch": "name:s, head:s7?, commitCount:i", "Commit": "id:s7, message:s, ts:ms, files:i", "Diff": "ref:s?, added:a[s], modified:a[s], deleted:a[s]", "Directory": "path:s, entries:a[s], fileCount:i, mtime:ms", "ExportArtifact": "format:e[json|bundle], size:i, ts:ms", "FileTree": "root:s, nodes:a[{path,type,size?}], fileCount:i", "Preview": "path:s, sizeBytes:i, inlined:a[{path,kind}], ts:ms", "Scaffold": "kind:e[vanilla|spa|markdown|canvas], files:a[s], entry:s?", "Status": "clean:b, added:a[s], modified:a[s], deleted:a[s], commits:i", "ToolCall": "name:s, args:o, ok:b, result:s?, ts:ms", "VFile": "path:s, type:e, size:i, mtime:ms"}, "📦": {"repo (mcp/repo.js)": {"branch": "s", "branches": "m name:s → { head:s7? }", "commits": "a [{ id:s7, message:s, ts:ms, branch:s, snapshot:o }]", "directories": "Set<s> (explicit mkdir targets)", "files": "m path:s → { content:s, mtime:ms }", "name": "s", "staged": "m (reserved)"}}}');
