INSERT INTO "programs" VALUES('L2/scada/programs/web-llm/tools.json','4.2.3','🔧','tools','L4/sandbox/web-llm/modules/tools.js',NULL,'{"module": "L4/sandbox/web-llm/modules/tools.js", "name": "tools", "§": "4.2.3", "↑🖥️(via 🛰️)": ["sandbox.web-llm.tool.count", "sandbox.web-llm.tool.last (🏗️ToolCall UDT)"], "→": [{"flow": "executeTool ⊕ logRow", "in": "name:e, args:o", "name": "runToolCall", "out": "result:o"}, {"flow": "parseToolCalls ⊕ ∀ tc → runToolCall ⊕ onAfter", "in": "text:s, onAfter(tc,r)?", "name": "parseAndRunAll"}, {"flow": "TOOL.inc(count) ⊕ TOOL.write(last,🏗️ToolCall) ⊕ DOM.prepend(.tool-entry)", "in": "name,args,result", "name": "logRow"}], "和": true, "🏗️": "🔧", "📦": {"callCount": "i"}}');
INSERT INTO "programs" VALUES('L2/scada/programs/web-llm/voice.json','4.2.2','🎤','voice','L4/sandbox/web-llm/modules/voice.js',NULL,'{"module": "L4/sandbox/web-llm/modules/voice.js", "name": "voice", "§": "4.2.2", "↑🖥️(via 🛰️)": ["sandbox.web-llm.voice.micConnected", "sandbox.web-llm.voice.listening", "sandbox.web-llm.voice.state (🏗️Voice UDT)", "sandbox.web-llm.emotion.state (🏗️Emotion UDT)", "sandbox.web-llm.emotion.dominant"], "→": [{"flow": "getUserMedia(audio) ⊕ AudioContext ⊕ Analyser(fft=2048) ⊕ VOICE.write(micConnected,true)", "name": "setupMic"}, {"flow": "rAF → RMS, F0 (autocorrelation), formant→vowel, onset→pulseRate ⊕ emotion heuristics ⊕ ~250ms throttle → VOICE/EMOTION.write", "name": "analyzeLoop"}, {"flow": "new SpeechRecognition(continuous,interim) ⊕ auto-restart on end", "name": "setupRecognition"}, {"flow": "resume(audioCtx) ⊕ toggle micActive ⊕ recognition.start/stop", "name": "toggleListening"}, {"flow": "analyser? ∧ recognition? → start ⊕ VOICE.write(listening,true)", "name": "startListeningAuto"}, {"name": "emotionSnapshot", "out": "{dominant:s, values:o}"}], "和": true, "🏗️": "🎤", "📦": {"analyser": "AnalyserNode?", "audioCtx": "AudioContext?", "dominantEmo": "s", "emotions": {"anger": "f", "calm": "f", "curiosity": "f", "excitement": "f", "joy": "f", "sadness": "f"}, "micActive": "b", "recognition": "SpeechRecognition?", "voice": {"coherence": "f", "energy": "f", "f0": "f", "pDelta": "f", "pulseRate": "f", "rms": "f", "sustain": "f", "vowel": "e[oo|oh|ah|eh|ee]"}}}');
